import { useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';
import { fetchDestinations } from '../services/api';
import DestinationCard from '../components/DestinationCards';
import CreateDestination from '../components/DestinationsCreate';
import { GoogleMap, Marker } from '@react-google-maps/api';
import '../styles/GroupDetails.css';
import '../styles/Groups.css';

export default function Destinations() {
    const { state } = useLocation();
    const [groups, setGroups] = useState([]);
    const [showModal, setShowModal] = useState(false);

    
    
    const groupName = state?.name || "Nos destinations";
    const groupMembers = state?.members || [];


    useEffect(() => {
        fetchDestinations().then((data) => {
            setGroups(data);
        });
    }, []);

    console.log(groups.n); // Affiche les donnĂ©es des groupes

    return (
        <div className="groups-container">
            <div className="groups-header">
                <h1 className="groups-title">{groupName}</h1>

                {groupMembers.length > 0 && (
                    <p className="group-members">
                        Membres : {groupMembers.join(', ')}
                    </p>
                )}

                <button
                    className="create-group-button"
                    onClick={() => setShowModal(true)}
                >
                    CrĂ©er une destination
                </button>
            </div>

            {/* Google Maps avec marqueurs */}
            <GoogleMap
                mapContainerStyle={{
                    width: '100%',
                    height: '400px',
                    marginBottom: '20px',
                    borderRadius: '8px'
                }}
                center={{ lat: 43.6, lng: 1.433 }} // Point intermĂ©diaire par dĂ©faut
                zoom={2}
                onLoad={() => console.log('Map loaded')} // VĂ©rifie que la carte se charge bien
            >
                {/* Afficher un marqueur pour chaque destination */}
                {groups.map((group) => 
                    group.location?.lat && group.location?.lng ? (
                        <Marker
                            key={group.id}
                            position={{
                                lat: group.location.lat,
                                lng: group.location.lng
                            }}
                            title={group.name}
                        />
                    ) : null
                )}
            </GoogleMap>

            {/* Cartes de destinations */}
            <div className="groups-grid">
            {
            groups.map((d) => (
                <DestinationCard
                key={d.id}
                id={d.id}
                name={d.name}
                image={d.image}
                comments={d.comments}
                priceHouse={parseFloat(d.priceHouse)}
                priceTravel={parseFloat(d.priceTravel)}
                proposedBy={d.proposedBy}
                members={d.members}
                dates={d.dates}
            />
            
            ))
        }

            </div>

            {/* Modal de crĂ©ation */}
            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <button className="close-modal" onClick={() => setShowModal(false)}>âś–</button>
                        <CreateDestination
                            onClose={() => setShowModal(false)}
                            onCreate={(newGroup) =>
                                setGroups(prev => [...prev, newGroup])
                            }
                        />
                    </div>
                </div>
            )}
        </div>
    );

}
